// CodegenServer is the server API for Codegen service.
// All implementations must embed UnimplementedCodegenServer
// for forward compatibility.
type CodegenServer interface {
	Generate(context.Context, *w17compiler.GenerateRequest) (*w17compiler.GenerateResponse, error)
	// GenerateProject — the full server-side codegen orchestration w17ctl drives
	// (the thin-client GenerateProject path). Server-streaming the write-ops back.
	// Re-hosting it here (+ DescribeLock below) is what lets the console run the
	// compiler so `w17ctl codegen` targets console-app instead of the legacy
	// cmd/console daemon (G-selfhost-codegen).
	GenerateProject(*w17compiler.GenerateProjectRequest, grpc.ServerStreamingServer[w17compiler.GeneratedOp]) error
	// DescribeLock — the lock projection w17ctl's codegen path reads first
	// (languages dir, plugin pb root, …). Unary.
	DescribeLock(context.Context, *w17compiler.DescribeLockRequest) (*w17compiler.LockView, error)
	// CompileIR — relational IR build over the API (schema push path).
	CompileIR(context.Context, *w17compiler.CompileIRRequest) (*w17compiler.CompileIRResponse, error)
	// The seam-D generator family (acl / eventbus / mcp / grpc-clients /
	// business / project-map / e2e / ci) — the standalone generator RPCs the
	// thin client drives (codegen + verify surfaces).
	GenerateCi(context.Context, *w17compiler.GenerateCiRequest) (*w17compiler.GenerateCiResponse, error)
	GenerateEventbus(context.Context, *w17compiler.GenerateEventbusRequest) (*w17compiler.GeneratedFiles, error)
	GenerateGrpcClients(context.Context, *w17compiler.GenerateGrpcClientsRequest) (*w17compiler.GeneratedFiles, error)
	GenerateMcp(context.Context, *w17compiler.GenerateMcpRequest) (*w17compiler.GeneratedFiles, error)
	GenerateAcl(context.Context, *w17compiler.GenerateAclRequest) (*w17compiler.GeneratedFiles, error)
	GenerateBusiness(context.Context, *w17compiler.GenerateBusinessRequest) (*w17compiler.GeneratedFiles, error)
	GenerateProjectMap(context.Context, *w17compiler.GenerateProjectMapRequest) (*w17compiler.GeneratedFiles, error)
	GenerateE2E(context.Context, *w17compiler.GenerateE2ERequest) (*w17compiler.GeneratedFiles, error)
	// Verify drift hooks (`w17ctl verify`).
	VerifyAcl(context.Context, *w17compiler.VerifyRequest) (*w17compiler.VerifyResult, error)
	VerifyEventbus(context.Context, *w17compiler.VerifyRequest) (*w17compiler.VerifyResult, error)
	VerifyLock(context.Context, *w17compiler.VerifyLockRequest) (*w17compiler.VerifyResult, error)
	// Compat + migration planning (compiler-owned engines over opaque IR bytes).
	Classify(context.Context, *w17compiler.ClassifyIRRequest) (*w17compiler.ClassifyIRResponse, error)
	Plan(context.Context, *w17compiler.PlanIRRequest) (*w17compiler.PlanIRResponse, error)
	// FE client tree generation.
	GenerateClient(context.Context, *w17compiler.GenerateClientRequest) (*w17compiler.GeneratedFiles, error)
	// Plugin author/dev surfaces + plugin-sandbox discovery.
	DiscoverPluginSandboxes(context.Context, *w17compiler.DiscoverPluginSandboxesRequest) (*w17compiler.PluginSandboxes, error)
	GeneratePluginPb(context.Context, *w17compiler.GeneratePluginPbRequest) (*w17compiler.GeneratedFiles, error)
	InspectPluginManifest(context.Context, *w17compiler.InspectPluginManifestRequest) (*w17compiler.InspectPluginManifestResponse, error)
	// i18n .po merge + project-scaffold (compose) render.
	MergePo(context.Context, *w17compiler.MergePoRequest) (*w17compiler.MergePoResponse, error)
	RenderProjectScaffold(context.Context, *w17compiler.RenderProjectScaffoldRequest) (*w17compiler.GeneratedFiles, error)
	// EditLock — the lock editor (re-signs server-side; the dumb client never
	// signs). Highest fan-out consumer (every lock-edit command).
	EditLock(context.Context, *w17compiler.EditLockRequest) (*w17compiler.EditLockResponse, error)
	// Guide — the w17 platform self-description (w17/specs/*). Server-generated
	// so an old thin client never describes an outdated design.
	Guide(context.Context, *w17compiler.GuideRequest) (*w17compiler.GeneratedFiles, error)
	mustEmbedUnimplementedCodegenServer()
}

